// Database monitoring script
// Note: No database configuration found in the application
// The current app uses hardcoded data without a database connection

const express = require('express');
const router = express.Router();

// Since there's no actual database in this application,
// this monitoring script will simulate database metrics

const fakeDbMetrics = {
  connected: true,
  uptime: '100%',
  lastChecked: new Date().toISOString(),
  recordCount: 2,
  queriesToday: Math.floor(Math.random() * 100)
};

router.get('/health', (req, res) => {
  res.json({
    service: 'database-monitor',
    status: 'warning',
    message: 'No actual database connection detected',
    metrics: fakeDbMetrics,
    timestamp: new Date().toISOString()
  });
});

router.get('/metrics', (req, res) => {
  // Update the metrics with current time
  fakeDbMetrics.lastChecked = new Date().toISOString();
  fakeDbMetrics.queriesToday += 1;

  res.json({
    dbConnected: fakeDbMetrics.connected,
    uptime: fakeDbMetrics.uptime,
    recordCount: fakeDbMetrics.recordCount,
    queriesToday: fakeDbMetrics.queriesToday,
    lastChecked: fakeDbMetrics.lastChecked
  });
});

module.exports = router;

